import{_ as d,C as g,o as a,c as s,a5 as n,b as r,w as e,a as o,E as l,a4 as E}from"./chunks/framework.sOZL8giL.js";const _=JSON.parse('{"title":"Agent的本质","description":"","frontmatter":{},"headers":[],"relativePath":"03-Agent基础/01-Agent的本质.md","filePath":"03-Agent基础/01-Agent的本质.md","lastUpdated":1774181700000}'),i={name:"03-Agent基础/01-Agent的本质.md"};function B(h,t,p,u,b,f){const A=g("Mermaid");return a(),s("div",null,[t[2]||(t[2]=n('<h1 id="agent的本质" tabindex="-1">Agent的本质 <a class="header-anchor" href="#agent的本质" aria-label="Permalink to &quot;Agent的本质&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 3 模块的第 1 章。</p></blockquote><p>从&quot;说一句动一句&quot;到&quot;自主做事&quot;——Agent 不是更会聊天的 Chatbot，而是系统让它能安全地做事。</p><hr><h2 id="agent-到底是什么" tabindex="-1">Agent 到底是什么？ <a class="header-anchor" href="#agent-到底是什么" aria-label="Permalink to &quot;Agent 到底是什么？&quot;">​</a></h2><p>Agent 就是一个能自己干活的 AI。更工程一点：你给它一个目标、一个工具箱和一套边界（预算/权限/审批/沙箱），它在循环里推进任务，直到完成或停下。</p><p>核心就四样东西：<strong>Agent = 大脑(LLM) + 手脚(Tools) + 记忆(Memory) + 主见(Autonomy)</strong>。</p>',7)),(a(),r(E,null,{default:e(()=>[l(A,{id:"mermaid-21",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BAgent%5D%20--%3E%20B%5B%E5%A4%A7%E8%84%91%20LLM%3Cbr%2F%3E%E6%80%9D%E8%80%83%E5%86%B3%E5%AE%9A%E4%B8%8B%E4%B8%80%E6%AD%A5%5D%0A%20%20%20%20A%20--%3E%20C%5B%E6%89%8B%E8%84%9A%20Tools%3Cbr%2F%3E%E6%90%9C%E7%B4%A2%2F%E8%AF%BB%E5%86%99%2F%E8%B0%83API%5D%0A%20%20%20%20A%20--%3E%20D%5B%E8%AE%B0%E5%BF%86%20Memory%3Cbr%2F%3E%E7%9F%AD%E6%9C%9F%E4%B8%8A%E4%B8%8B%E6%96%87%2B%E9%95%BF%E6%9C%9F%E7%9F%A5%E8%AF%86%5D%0A%20%20%20%20A%20--%3E%20E%5B%E4%B8%BB%E8%A7%81%20Autonomy%3Cbr%2F%3E%E8%87%AA%E5%B7%B1%E5%81%9A%E5%86%B3%E5%AE%9A%E4%B8%8D%E9%9D%A0%E6%8C%87%E4%BB%A4%5D%0A%20%20%20%20B%20--%3E%20F%5B%E8%87%AA%E4%B8%BB%E5%AE%8C%E6%88%90%E4%BB%BB%E5%8A%A1%5D%0A%20%20%20%20C%20--%3E%20F%0A%20%20%20%20D%20--%3E%20F%0A%20%20%20%20E%20--%3E%20F%0A%20%20%20%20F%20--%3E%20G%7B%E5%8F%AF%E6%8E%A7%E6%80%A7%7D%0A%20%20%20%20G%20--%3E%20H%5B%E4%BA%BA%E7%B1%BB%E8%AE%BE%E5%AE%9A%E7%9B%AE%E6%A0%87%5D%0A%20%20%20%20G%20--%3E%20I%5B%E4%BA%BA%E7%B1%BB%E7%9B%91%E7%9D%A3%E8%BF%87%E7%A8%8B%5D%0A%20%20%20%20G%20--%3E%20J%5B%E4%BA%BA%E7%B1%BB%E9%AA%8C%E6%94%B6%E7%BB%93%E6%9E%9C%5D%0A"})]),fallback:e(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=n('<blockquote><p>💡 <strong>图解：</strong> 四个组件缺一不可——光有大脑没手脚是聊天机器人，光有手脚没主见是脚本，有主见没记忆是失忆症患者。</p></blockquote><p>大脑负责思考决定下一步干什么。手脚负责执行——搜索网页、读写文件、调用 API。记忆负责记住之前发生了什么——短期记忆是当前对话上下文，长期记忆是跨会话知识积累。主见最关键——它得自己做决定，不是你说一步它动一步。</p><p>ChatGPT 和 Agent 的分水岭：ChatGPT 说一句回一句，你得不停追问引导。让它订机票，它只会给你航班信息让你去携程。真正的 Agent 区别不是更会聊天，而是系统让它能安全地做事——能用工具、能拿到授权、关键节点会停下来确认、全过程可追溯。</p><h3 id="与传统软件的区别" tabindex="-1">与传统软件的区别 <a class="header-anchor" href="#与传统软件的区别" aria-label="Permalink to &quot;与传统软件的区别&quot;">​</a></h3><p>传统软件是确定性的：给定输入 A，必然产出 B。Agent 是概率性的：给定输入 A，它会&quot;思考&quot;该怎么做，可能产出 B 也可能产出 C。这带来了灵活性，也带来了不确定性。生产环境中如何控制这种不确定性，是 Agent 系统设计的核心挑战。</p><hr><h2 id="自主性等级" tabindex="-1">自主性等级 <a class="header-anchor" href="#自主性等级" aria-label="Permalink to &quot;自主性等级&quot;">​</a></h2><p>Agent 不是非黑即白的概念，而是一个谱系：</p><table tabindex="0"><thead><tr><th>等级</th><th>名称</th><th>核心能力</th></tr></thead><tbody><tr><td><strong>L0</strong></td><td>Chatbot</td><td>问一句答一句，无工具调用</td></tr><tr><td><strong>L1</strong></td><td>Tool Agent</td><td>能调用工具但无多步推理</td></tr><tr><td><strong>L2</strong></td><td>ReAct Agent</td><td>思考→行动→观察循环</td></tr><tr><td><strong>L3</strong></td><td>Planning Agent</td><td>先拆解计划再逐个执行</td></tr><tr><td><strong>L4</strong></td><td>Multi-Agent</td><td>多个 Agent 分工协作</td></tr><tr><td><strong>L5</strong></td><td>Autonomous</td><td>长期自主运行自我迭代</td></tr></tbody></table><p>大多数人用的是 L0-L1。L2-L4 是实际可构建的范围。L5 目前还没有真正可靠的实现，谁说有可以持保留态度。</p>',10)),(a(),r(E,null,{default:e(()=>[l(A,{id:"mermaid-132",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20L0%5BL0%20Chatbot%3Cbr%2F%3E%E9%97%AE%E4%B8%80%E5%8F%A5%E7%AD%94%E4%B8%80%E5%8F%A5%5D%20--%3E%20L1%5BL1%20Tool%20Agent%3Cbr%2F%3E%E8%83%BD%E8%B0%83%E5%B7%A5%E5%85%B7%5D%0A%20%20%20%20L1%20--%3E%20L2%5BL2%20ReAct%20Agent%3Cbr%2F%3E%E6%80%9D%E8%80%83%E2%86%92%E8%A1%8C%E5%8A%A8%E2%86%92%E8%A7%82%E5%AF%9F%5D%0A%20%20%20%20L2%20--%3E%20L3%5BL3%20Planning%20Agent%3Cbr%2F%3E%E5%85%88%E6%8B%86%E8%A7%A3%E8%AE%A1%E5%88%92%5D%0A%20%20%20%20L3%20--%3E%20L4%5BL4%20Multi-Agent%3Cbr%2F%3E%E5%A4%9AAgent%E5%88%86%E5%B7%A5%E5%8D%8F%E4%BD%9C%5D%0A%20%20%20%20L4%20--%3E%20L5%5BL5%20Autonomous%3Cbr%2F%3E%E9%95%BF%E6%9C%9F%E8%87%AA%E4%B8%BB%E8%BF%AD%E4%BB%A3%5D%0A%20%20%20%20style%20L0%20fill%3A%23ddd%0A%20%20%20%20style%20L1%20fill%3A%23ccc%0A%20%20%20%20style%20L2%20fill%3A%238cf%0A%20%20%20%20style%20L3%20fill%3A%236af%0A%20%20%20%20style%20L4%20fill%3A%2348f%0A%20%20%20%20style%20L5%20fill%3A%23f90%0A"})]),fallback:e(()=>[...t[1]||(t[1]=[o(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=n('<blockquote><p>💡 <strong>图解：</strong> 自主性不是开关而是光谱——L2-L4 是实际可构建范围，L5 目前更像愿景而非现实。</p></blockquote><hr><h2 id="一个真实的例子" tabindex="-1">一个真实的例子 <a class="header-anchor" href="#一个真实的例子" aria-label="Permalink to &quot;一个真实的例子&quot;">​</a></h2><p>你让 Agent &quot;研究字节跳动，写一份分析报告&quot;。</p><p>Chatbot 给你一段训练数据里的信息然后说&quot;需要最新信息请自行搜索&quot;。</p><p>Agent 的做法：任务分解（搜索背景 → 查产品线 → 分析竞争对手 → 查财务信息 → 综合写报告），逐个执行每个子任务调用搜索工具获取信息，自我检查哪些信息够了哪些需要补充，最后综合输出结构化报告。</p><p>整个过程你只说了一句话。这就是 Agent。</p><hr><h2 id="能做什么-不能做什么" tabindex="-1">能做什么，不能做什么 <a class="header-anchor" href="#能做什么-不能做什么" aria-label="Permalink to &quot;能做什么，不能做什么&quot;">​</a></h2><p><strong>擅长</strong>：目标明确、步骤可拆解、结果可验证、信息可获取、重复性高。</p><p><strong>不擅长</strong>：开放性创意、主观判断、复杂人际、高风险决策、不可逆副作用、实时物理操作。</p><p>一个简单的判断方法：如果这个任务你交给一个实习生，能用文字清楚地告诉他怎么做，大概率适合 Agent。如果自己都说不清楚&quot;怎么算做好了&quot;，那 Agent 也搞不定。</p><p>很多事情不是不能做，而是必须加确认点才敢做——付款、发布、删除、群发邮件，默认都应该是人类确认 Agent 执行。</p><hr><h2 id="技术演进" tabindex="-1">技术演进 <a class="header-anchor" href="#技术演进" aria-label="Permalink to &quot;技术演进&quot;">​</a></h2><p>2022 年前是规则驱动（Siri、Alexa 本质是规则引擎+意图识别）。2023 年 LLM 成为大脑（GPT-4 等大模型让 LLM 驱动工具调用成为可能）。2023-2024 年 ReAct 与 Function Calling 成为关键突破。2024-2025 年多 Agent 与生产化成为主流，企业关注成本控制、安全性、可靠性、可观测性。</p><hr><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>Agent ≠ ChatGPT + 插件</strong>：插件只是工具，Agent 核心是自主决策循环。有工具不代表是 Agent，能自己决定什么时候用什么工具才是。</p><p><strong>Agent 不能替代人类</strong>：至少现在不能。Agent 是增强工具，能处理重复性结构化任务，但需要人类设定目标、监督过程、验收结果。</p><p><strong>Agent 不是越自主越好</strong>：自主性越高不确定性越大。生产环境需要在自主性和可控性之间找平衡。</p><p><strong>最强模型 ≠ 最好 Agent</strong>：模型能力只是基础。Agent 系统质量取决于工具设计、Prompt 清晰度、错误处理、架构扩展性。</p><hr><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">把 Agent 当 Chatbot 用（每次一条消息等回复）</td><td style="text-align:left;">一次给出完整任务描述 + 约束 + 验证标准</td><td style="text-align:left;">Agent 需要完整上下文才能自主决策</td></tr><tr><td style="text-align:left;">没有终止条件就启动循环</td><td style="text-align:left;">明确定义「成功」和「失败」的判定标准</td><td style="text-align:left;">没有终止条件的 Agent 会无限循环</td></tr><tr><td style="text-align:left;">给 Agent 所有工具都配上</td><td style="text-align:left;">只给完成任务必需的最少工具</td><td style="text-align:left;">工具过多会导致选择困难</td></tr><tr><td style="text-align:left;">期望 Agent 一次完美完成</td><td style="text-align:left;">设计 ReAct 循环，允许多轮尝试和修正</td><td style="text-align:left;">Agent 的价值在于迭代</td></tr></tbody></table><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>Agent 定义：能自主完成任务的 AI 系统，核心是自己做决定</li><li>四个组件：大脑(LLM) + 手脚(Tools) + 记忆(Memory) + 主见(Autonomy)</li><li>自主性等级 L0-L5，L2-L4 是实际可构建范围</li><li>适用场景：目标明确、步骤可拆解、结果可验证</li></ul><hr><p><strong>下一章</strong>: <a href="./02-工具与协议.html">工具与协议</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/02-上下文工程/">← 上一模块: 上下文工程</a> | <a href="/04-多Agent架构/">下一模块: 多Agent架构 →</a></p>',32))])}const c=d(i,[["render",B]]);export{_ as __pageData,c as default};
